function withoutCarriageReturn(line: string): string {
  return line.endsWith("\r") ? line.slice(0, -1) : line;
}

export class Utf8LineDecoder {
  private carry = "";

  push(chunk: Uint8Array): string[] {
    const text = this.carry + new TextDecoder("utf-8").decode(chunk);
    const pieces = text.split("\n");
    this.carry = pieces.pop() ?? "";
    return pieces.map(withoutCarriageReturn);
  }

  finish(): string[] {
    if (this.carry.length === 0) {
      return [];
    }
    const finalLine = withoutCarriageReturn(this.carry);
    this.carry = "";
    return [finalLine];
  }
}

