import { Utf8LineDecoder } from "./utf8Lines.ts";

export interface TelemetryMessage {
  [key: string]: unknown;
}

export function readMessages(chunks: Iterable<Uint8Array>): TelemetryMessage[] {
  const decoder = new Utf8LineDecoder();
  const lines: string[] = [];

  for (const chunk of chunks) {
    lines.push(...decoder.push(chunk));
  }

  return lines
    .filter((line) => line.length > 0)
    .map((line) => JSON.parse(line) as TelemetryMessage);
}

