import assert from "node:assert/strict";
import test from "node:test";

import { readMessages } from "../src/messageReader.ts";

test("newline-terminated ASCII messages decode across aligned chunks", () => {
  const encoder = new TextEncoder();
  const messages = readMessages([
    encoder.encode('{"id":1,"status":"ok"}\n'),
    encoder.encode('{"id":2,"status":"ready"}\n'),
  ]);

  assert.deepEqual(messages, [
    { id: 1, status: "ok" },
    { id: 2, status: "ready" },
  ]);
});
